import java.util.Base64;

public class SecureDeserializationDemo {

    public static void main(String[] args) {
        String userInput = "cGFzc3dvcmQ="; // Base64 encoded serialized object

        try {
            // Decode the Base64 encoded input
            byte[] decodedInput = Base64.getDecoder().decode(userInput);

            // Create a secure ObjectInputStream with ObjectInputFilter to prevent malicious object creation
            ObjectInputStream ois = new ObjectInputStream(new ByteArrayInputStream(decodedInput));
            ois.setObjectInputFilter(filter -> {
                if (filter.allowedClasses().size() == 0) {
                    throw new InvalidObjectException("No allowed classes specified");
                }
                return filter;
            });

            // Deserialize the object from input
            Object obj = ois.readObject();

            // Perform operations on the deserialized object safely
